// LESSON: JavaFX Layout Panes - Reference Page 2.
// You will learn: Arrange controls with VBox, HBox, BorderPane, and GridPane.
import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.GridPane;
import javafx.scene.layout.HBox;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class JavaFxLayoutPaneReference extends Application {
  public static void main(String[] args) {
    launch(args);
  }

  @Override
  public void start(Stage stage) {
    VBox root = new VBox(12);
    root.setPadding(new Insets(12));
    root.getChildren().addAll(exampleVBoxHBox(), exampleBorderPane(), exampleGridPane());
    stage.setScene(new Scene(root, 460, 360));
    stage.setTitle("Layout panes");
    stage.show();
  }

  private VBox exampleVBoxHBox() {
    VBox box = new VBox(6);
    HBox row = new HBox(8);
    row.setAlignment(Pos.CENTER_LEFT);
    row.getChildren().addAll(new Button("Save"), new Button("Cancel"));
    box.getChildren().addAll(new Label("EXAMPLE 1: VBox and HBox"), row);
    return box;
  }

  private BorderPane exampleBorderPane() {
    BorderPane pane = new BorderPane();
    pane.setTop(new Label("EXAMPLE 2: BorderPane top"));
    pane.setCenter(new Label("Center is for main content"));
    pane.setBottom(new Button("Bottom button"));
    return pane;
  }

  private GridPane exampleGridPane() {
    GridPane grid = new GridPane();
    grid.setHgap(8);
    grid.setVgap(6);
    grid.add(new Label("EXAMPLE 3: GridPane"), 0, 0);
    grid.add(new Label("Name:"), 0, 1);
    grid.add(new Button("Send"), 1, 1);
    return grid;
  }
}
